const testHMACSecret = "test-secret"

func newVerifierWithHMAC(t *testing.T) *auth.Verifier {
	t.Helper()
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		json.NewEncoder(w).Encode(map[string]any{"keys": []any{}})
	}))
	t.Cleanup(srv.Close)
	return auth.NewVerifier(testHMACSecret, srv.URL)
}

func newVerifierWithEC(t *testing.T, kid string, key *ecdsa.PrivateKey) *auth.Verifier {
	t.Helper()
	ecdhKey, err := key.PublicKey.ECDH()
	require.NoError(t, err)
	raw := ecdhKey.Bytes() // 04 || X (32 bytes) || Y (32 bytes)
	xBytes := raw[1:33]
	yBytes := raw[33:65]
	jwks := map[string]any{
		"keys": []any{
			map[string]any{
				"kid": kid,
				"kty": "EC",
				"crv": "P-256",
				"x":   base64.RawURLEncoding.EncodeToString(xBytes),
				"y":   base64.RawURLEncoding.EncodeToString(yBytes),
			},
		},
	}
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		json.NewEncoder(w).Encode(jwks)
	}))
	t.Cleanup(srv.Close)
	return auth.NewVerifier("", srv.URL)
}

func signHMAC(t *testing.T, secret string, expired bool, userID string) string {
	t.Helper()
	exp := time.Now().Add(time.Hour)
	if expired {
		exp = time.Now().Add(-time.Hour)
	}
	token, err := jwt.NewWithClaims(jwt.SigningMethodHS256, jwt.MapClaims{
		"sub":          "auth-user-id",
		"app_metadata": map[string]any{"user_id": userID},
		"exp":          exp.Unix(),
	}).SignedString([]byte(secret))
	require.NoError(t, err)
	return token
}

func signEC(t *testing.T, kid string, key *ecdsa.PrivateKey, expired bool, userID string) string {
	t.Helper()
	exp := time.Now().Add(time.Hour)
	if expired {
		exp = time.Now().Add(-time.Hour)
	}
	tok := jwt.NewWithClaims(jwt.SigningMethodES256, jwt.MapClaims{
		"sub":          "auth-user-id",
		"app_metadata": map[string]any{"user_id": userID},
		"exp":          exp.Unix(),
	})
	tok.Header["kid"] = kid
	token, err := tok.SignedString(key)
	require.NoError(t, err)
	return token
}

func signHMACWithClaims(t *testing.T, secret string, claims jwt.MapClaims) string {
	t.Helper()
	if _, ok := claims["exp"]; !ok {
		claims["exp"] = time.Now().Add(time.Hour).Unix()
	}
	token, err := jwt.NewWithClaims(jwt.SigningMethodHS256, claims).SignedString([]byte(secret))
	require.NoError(t, err)
	return token
}

